import { Component } from '@angular/core';
import { CommonModule } from '@angular/common';
import { NavigationService } from '../../../service/native/navigation/navigation.service';

@Component({
  selector: 'app-header',
  standalone: true,
  imports: [CommonModule],
  template: `
  <div class="header">
    <p class="header_text">Swee Seng</p>

<ul><li>hello World </li></ul>

    <ul *ngforEach="let configuredRoute of navigationService.ConfiguredRoutes()">
    <li>hi</li>
      <li>{{configuredRoute}}</li>
    </ul>
  </div>
  `,
  styleUrls: ['./header.component.css']
})
export class HeaderComponent {
  constructor(protected navigationService: NavigationService) { }
}
